<script setup lang="ts">
import{computed,ref}from'vue';import type{Customer}from'@/types/customer';import type{SourceId,SourceImport}from'@/types/dataSource';import{SOURCE_CONFIG,emptySource,mergeSources,parseSourceCsv,sourceIds}from'@/utils/multiSourceData'
const props=defineProps<{customers:Customer[];sourceLabel:string}>();const emit=defineEmits<{applyCustomers:[Customer[],string];resetData:[]}>();const imports=ref<Record<SourceId,SourceImport>>(Object.fromEntries(sourceIds.map(id=>[id,emptySource(id)])) as Record<SourceId,SourceImport>);const summary=computed(()=>mergeSources(imports.value));const canApply=computed(()=>summary.value.customers.length>0&&!summary.value.missingRequiredSources.length)
const money=(n:number)=>`RM ${n.toLocaleString('en-MY')}`
function download(content:string,name:string){const url=URL.createObjectURL(new Blob([content],{type:'text/csv'}));const a=document.createElement('a');a.href=url;a.download=name;a.click();URL.revokeObjectURL(url)}
function template(id:SourceId){download(SOURCE_CONFIG[id].template,`${id}.csv`)}
async function upload(id:SourceId,event:Event){const input=event.target as HTMLInputElement,file=input.files?.[0];input.value='';if(!file)return;imports.value={...imports.value,[id]:parseSourceCsv(id,await file.text(),file.name)}}
function clear(id:SourceId){imports.value={...imports.value,[id]:emptySource(id)}}
function apply(){if(canApply.value)emit('applyCustomers',summary.value.customers,`Five-source browser import · ${new Date().toLocaleString('en-MY')}`)}
</script>
<template><div class="data-studio page-stack"><section class="page-intro"><div><span class="eyebrow">Browser-only import</span><h2>Multi-source Data Studio</h2><p>Load five independent CSV demo connectors, validate each source, and merge records by customerId. No external platform is connected.</p></div><div class="active"><span>Active dataset</span><strong>{{sourceLabel}}</strong><small>{{customers.length}} customers</small></div></section>
<section class="honesty"><strong>CSV demo connector</strong><span>Sample dataset · Browser-only import · Production integrations planned</span></section>
<section class="source-grid"><article v-for="id in sourceIds" :key="id" class="source-card panel"><header><div><span class="eyebrow">{{SOURCE_CONFIG[id].optional?'Optional source':'Required source'}}</span><h3>{{SOURCE_CONFIG[id].label}}</h3></div><span class="status" :class="imports[id].status.toLowerCase().replace(' ','-')">{{imports[id].status}}</span></header><p class="schema">{{SOURCE_CONFIG[id].required.join(' · ')}}</p><label class="upload"><input type="file" accept=".csv,text/csv" @change="upload(id,$event)"><span>{{imports[id].fileName||'Choose CSV file'}}</span></label><div class="source-stats"><div><span>Rows</span><strong>{{imports[id].rowsDetected}}</strong></div><div><span>Valid</span><strong>{{imports[id].validRows}}</strong></div><div><span>Invalid</span><strong>{{imports[id].invalidRows}}</strong></div><div><span>Duplicates</span><strong>{{imports[id].duplicates}}</strong></div></div><small class="imported">{{imports[id].importedAt?`Last imported ${new Date(imports[id].importedAt).toLocaleString('en-MY')}`:'Not imported in this session'}}</small><ul v-if="imports[id].issues.length"><li v-for="issue in imports[id].issues.slice(0,3)" :key="`${issue.row}-${issue.message}`">Row {{issue.row}}: {{issue.message}}</li></ul><footer><button @click="template(id)">Download template</button><button v-if="imports[id].status!=='Not loaded'" @click="clear(id)">Clear</button></footer></article></section>
<section class="merge panel"><div class="panel-heading"><div><span class="eyebrow">Merge validation</span><h3>Customer identity and completeness</h3><p>Accounts are the master identity source; all other records are matched using customerId.</p></div><span class="completeness">{{summary.completenessPct}}% complete</span></div><div class="merge-grid"><article><span>Matched customers</span><strong>{{summary.matchedCustomers}}</strong></article><article><span>Unmatched source records</span><strong>{{summary.unmatchedRecords}}</strong></article><article><span>Duplicate customer IDs</span><strong>{{summary.duplicateCustomerIds}}</strong></article><article><span>Final merged customers</span><strong>{{summary.finalCustomerCount}}</strong></article><article><span>Invalid dates</span><strong>{{summary.invalidDates}}</strong></article><article><span>Invalid numeric ranges</span><strong>{{summary.invalidNumericRanges}}</strong></article></div><div class="missing"><p><strong>Missing required:</strong> {{summary.missingRequiredSources.length?summary.missingRequiredSources.join(', '):'None'}}</p><p><strong>Missing optional:</strong> {{summary.missingOptionalSources.length?summary.missingOptionalSources.join(', '):'None'}}</p></div><div class="actions"><button @click="emit('resetData')">Restore curated synthetic demo</button><button class="primary-button" :disabled="!canApply" @click="apply">Apply merged dataset</button></div></section>
<section class="panel preview"><div class="panel-heading"><div><span class="eyebrow">Merged preview</span><h3>Final customer records</h3></div></div><div class="preview-row header"><span>Customer</span><span>Plan</span><span>MRR</span><span>Source coverage</span><span>Risk indicator</span></div><div v-for="customer in summary.customers.slice(0,8)" :key="customer.id" class="preview-row"><strong>{{customer.companyName}}</strong><span>{{customer.plan}}</span><span>{{money(customer.monthlyRevenue)}}</span><span>{{Object.values(customer.dataAvailability!).filter(Boolean).length}} / 5</span><span>{{customer.churnProbability}} · {{customer.riskLevel}}</span></div><p v-if="!summary.customers.length" class="empty">Load an account master file to build the merged customer portfolio.</p></section></div></template>
<style scoped>.data-studio{max-width:1540px;margin:auto;padding:32px clamp(20px,3vw,48px) 56px}.page-intro,.panel-heading,.source-card header,.source-card footer,.actions{display:flex;align-items:center;justify-content:space-between;gap:16px}.active{min-width:230px;padding:15px;border:1px solid var(--color-border);border-radius:16px}.active span,.active strong,.active small{display:block}.active span,.active small{color:var(--color-muted);font-size:12px}.honesty{display:flex;gap:14px;padding:17px;border-radius:16px;color:var(--color-brown);background:var(--color-peach)}.source-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}.source-card{padding:20px;border-radius:20px}.source-card h3{margin:5px 0;font:400 24px var(--font-display)}.status{padding:6px 10px;border-radius:999px;font-size:12px;background:var(--color-mist)}.status.ready{color:var(--color-success);background:var(--color-success-soft)}.status.has-issues{color:var(--color-danger);background:var(--color-danger-soft)}.schema{min-height:44px;color:var(--color-muted);font-size:12px}.upload{display:block;padding:18px;border:1px dashed var(--color-border-strong);border-radius:14px;text-align:center}.upload input{display:none}.source-stats,.merge-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-top:14px}.source-stats div,.merge-grid article{padding:10px;border-radius:10px;background:var(--color-mist)}.source-stats span,.source-stats strong,.merge-grid span,.merge-grid strong{display:block}.source-stats span,.merge-grid span{color:var(--color-muted);font-size:12px}.source-stats strong,.merge-grid strong{margin-top:4px;font-size:18px}.imported{display:block;margin:12px 0;color:var(--color-muted)}.source-card ul{padding-left:18px;color:var(--color-danger);font-size:12px}.source-card footer button,.actions button{padding:9px 12px;border:1px solid var(--color-border);border-radius:10px;background:#fff}.merge,.preview{padding:24px;border-radius:22px}.panel-heading h3{margin:5px 0;font:400 28px var(--font-display)}.panel-heading p{margin:4px 0;color:var(--color-muted)}.completeness{font:400 32px var(--font-display)}.merge-grid{grid-template-columns:repeat(6,1fr)}.missing{display:flex;gap:24px;margin-top:16px}.actions{justify-content:flex-end;margin-top:16px}.primary-button:disabled{opacity:.45;cursor:not-allowed}.preview-row{display:grid;grid-template-columns:1.4fr .7fr .7fr 1fr 1fr;gap:12px;padding:13px 0;border-top:1px solid var(--color-border)}.preview-row.header{margin-top:15px;color:var(--color-muted);font-size:12px}.empty{padding:30px;text-align:center;color:var(--color-muted)}@media(max-width:1100px){.source-grid{grid-template-columns:1fr 1fr}.merge-grid{grid-template-columns:repeat(3,1fr)}}@media(max-width:700px){.page-intro,.honesty,.missing{align-items:start;flex-direction:column}.source-grid{grid-template-columns:1fr}.active{width:100%}.merge-grid,.source-stats{grid-template-columns:1fr 1fr}.preview{overflow-x:auto}.preview-row{min-width:700px}}</style>
